   1 | import { TriggerAction, type ISdk } from "iii-sdk";
   2 | import type { RawObservation, HookPayload } from "../types.js";
   3 | import { KV, STREAM, generateId } from "../state/schema.js";
   4 | import { StateKV } from "../state/kv.js";
   5 | import { stripPrivateData } from "./privacy.js";
   6 | import { DedupMap } from "./dedup.js";
   7 | import { withKeyedLock } from "../state/keyed-mutex.js";
   8 | import { isAutoCompressEnabled } from "../config.js";
   9 | import { buildSyntheticCompression } from "./compress-synthetic.js";
  10 | import { getSearchIndex, vectorIndexAddGuarded } from "./search.js";
  11 | import { getAgentId } from "../config.js";
  12 | import { logger } from "../logger.js";
  13 | 
  14 | export function extractImage(d: unknown): string | undefined {
  15 |   if (!d) return undefined;
  16 |   if (typeof d === "string") {
  17 |     if (d.startsWith("data:image/") || d.startsWith("iVBORw0KGgo") || d.startsWith("/9j/")) {
  18 |       return d;
  19 |     }
  20 |     return undefined;
  21 |   }
  22 |   if (typeof d === "object" && d !== null) {
  23 |     const obj = d as Record<string, unknown>;
  24 |     if (typeof obj["image_data"] === "string") return obj["image_data"];
  25 |     if (typeof obj["image_path"] === "string") return obj["image_path"];
  26 |     if (typeof obj["imageBase64"] === "string") return obj["imageBase64"];
  27 |     if (typeof obj["imagePath"] === "string") return obj["imagePath"];
  28 | 
  29 |     for (const key of Object.keys(obj)) {
  30 |       const match = extractImage(obj[key]);
  31 |       if (match) return match;
  32 |     }
  33 |   }
  34 |   return undefined;
  35 | }
  36 | 
  37 | export function registerObserveFunction(
  38 |   sdk: ISdk,
  39 |   kv: StateKV,
  40 |   dedupMap?: DedupMap,
  41 |   maxObservationsPerSession?: number,
  42 | ): void {
  43 |   sdk.registerFunction("mem::observe",
  44 |     async (payload: HookPayload) => {
  45 | 
  46 |       if (
  47 |         !payload?.sessionId ||
  48 |         typeof payload.sessionId !== "string" ||
  49 |         !payload.hookType ||
  50 |         typeof payload.hookType !== "string" ||
  51 |         !payload.timestamp ||
  52 |         typeof payload.timestamp !== "string"
  53 |       ) {
  54 |         return {
  55 |           success: false,
  56 |           error:
  57 |             "Invalid payload: sessionId, hookType, and timestamp are required",
  58 |         };
  59 |       }
  60 | 
  61 |       const obsId = generateId("obs");
  62 | 
  63 |       let dedupHash: string | undefined;
  64 |       if (dedupMap) {
  65 |         const d =
  66 |           typeof payload.data === "object" && payload.data !== null
  67 |             ? (payload.data as Record<string, unknown>)
  68 |             : {};
  69 |         const toolName = (d["tool_name"] as string) || payload.hookType;
  70 |         dedupHash = dedupMap.computeHash(
  71 |           payload.sessionId,
  72 |           toolName,
  73 |           d["tool_input"],
  74 |         );
  75 |         if (dedupMap.isDuplicate(dedupHash)) {
  76 |           return { deduplicated: true, sessionId: payload.sessionId };
  77 |         }
  78 |       }
  79 | 
  80 |       let sanitizedRaw: unknown = payload.data;
  81 |       try {
  82 |         const jsonStr = JSON.stringify(payload.data);
  83 |         const sanitized = stripPrivateData(jsonStr);
  84 |         sanitizedRaw = JSON.parse(sanitized);
  85 |       } catch {
  86 |         sanitizedRaw = stripPrivateData(String(payload.data));
  87 |       }
  88 | 
  89 |       const raw: RawObservation = {
  90 |         id: obsId,
  91 |         sessionId: payload.sessionId,
  92 |         timestamp: payload.timestamp,
  93 |         hookType: payload.hookType,
  94 |         raw: sanitizedRaw,
  95 |       };
  96 | 
  97 |       let extractedImage: string | undefined;
  98 | 
